<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> output </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> tokio_cmd</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">output</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
